/**
 * parser_asm_thin_c.c — parser.sx EMIT_HEAVY 第二遍 skip_heavy 桩 bl→C 目标。
 *
 * 与 lexer_gen.c / token.sx 布局一致；供 ast_pool k_asm_parser_thin_delegate 委托，
 * 避免 parse_peek / skip_balanced 等在宿主编译器 SU emit 失败（TokenKind / 深循环体）。
 */
#include <stddef.h>
#include <stdint.h>
#include <string.h>
#include "parser_asm_stretch_audit_gate.h"

/** 与 token.sx / token.h TokenKind 序一致（kind 字段为 int 比较）。 */
#include "token.h"
#include "ast.h"

struct parser_asm_token {
  int32_t kind;
  int32_t line;
  int32_t col;
  int32_t int_val;
  double float_val;
  uint8_t *ident;
  int32_t ident_len;
};

struct parser_asm_lexer {
  size_t pos;
  int32_t line;
  int32_t col;
};

struct parser_asm_lexer_result {
  struct parser_asm_lexer next_lex;
  struct parser_asm_token tok;
  size_t token_start;
};

/** 与 shux_slice_uint8_t / parser_gen []u8 指针路径一致。 */
struct parser_asm_slice_u8 {
  uint8_t *data;
  size_t length;
};

/** 与 parser.sx TrySkipAllowResult（allow(padding)）布局一致。 */
struct parser_asm_try_skip_allow_result {
  struct parser_asm_lexer lex;
  int32_t skipped;
  uint8_t _pad[4];
};

/** 与 parser.sx LibraryParseResult（allow(padding)）布局一致。 */
struct parser_asm_library_parse_result {
  uint8_t ok;
  uint8_t _pad[4];
  struct parser_asm_lexer next_lex;
  uint8_t name[64];
  int32_t name_len;
  uint8_t _pad_tail[4];
};

/** 与 parser.sx LibraryParseScanResult（allow(padding)）布局一致。 */
struct parser_asm_library_parse_scan_result {
  uint8_t ok;
  uint8_t _pad[4];
  struct parser_asm_lexer next_lex;
  uint8_t name[64];
  int32_t name_len;
  uint8_t param_name[32];
  int32_t param_name_len;
  uint8_t param_type_name[64];
  int32_t param_type_len;
  uint8_t field_name[64];
  int32_t field_len;
  uint8_t _pad_tail[4];
  uint8_t _pad_tail2[4];
};

/** 与 parser.sx CollectImportsResult 布局一致。 */
struct parser_asm_collect_imports_result {
  struct parser_asm_lexer lex;
};

/** 与 parser.sx ExternParseResult（allow(padding)）布局一致；侧车 grow 池键为 (uint8_t *)out。 */
struct parser_asm_extern_parse_result {
  struct parser_asm_lexer next_lex;
  uint8_t name[64];
  int32_t name_len;
  int32_t return_ty_ref;
  int32_t num_params;
};

/** 与 ast.sx Func 布局一致（parse_one_extern_and_add C 路径写 arena）。 */
struct ast_Func {
  uint8_t name[64];
  int32_t name_len;
  int32_t param_base;
  int32_t num_params;
  int32_t return_type_ref;
  int32_t body_ref;
  int32_t body_expr_ref;
  int32_t is_extern;
  int32_t is_async;
};

/** 与 parser_gen parser_OneFuncResult 布局一致（wire/parse_one_function_impl ABI）。 */
struct parser_asm_onefunc_result {
  int32_t ok;
  struct parser_asm_lexer next_lex;
  uint8_t name[64];
  int32_t name_len;
  int32_t num_params;
  int32_t num_consts;
  int32_t num_lets;
  int32_t has_if_expr;
  int32_t if_cond_true;
  int32_t if_then_val;
  int32_t if_else_val;
  int32_t if_cond_expr_ref;
  int32_t has_mul;
  int32_t mul_right_val;
  int32_t has_binop;
  int32_t binop_right_val;
  int32_t binop_left_param_idx;
  int32_t binop_right_param_idx;
  int32_t has_unary_neg;
  int32_t return_val;
  int32_t has_call_expr;
  uint8_t call_callee_name[64];
  int32_t call_callee_len;
  uint8_t return_var_name[64];
  int32_t return_var_name_len;
  int32_t return_expr_ref;
  int32_t has_explicit_return_kw;
  int32_t call_num_args;
  int32_t num_loops;
  int32_t num_for_loops;
  int32_t num_if_stmts;
  int32_t num_src_stmt_order;
  int32_t num_src_body_expr_stmts;
  int32_t func_return_type_ref;
};

